def total_due(items, tax_rate):
    gift_total = 0
    other_total = 0

    for item in items:
        line_total = item["price"] * item["quantity"]
        if item.get("category") == "gift_card":
            gift_total += line_total
        else:
            other_total += line_total

    subtotal = gift_total + other_total

    if subtotal > 100:
        subtotal = gift_total + other_total * 0.9

    return round(subtotal * (1 + tax_rate), 2)
